   216→    /**
   217→     * Memory-efficient batch create matching original behavior exactly
   218→     * Uses APOC iterate with MERGE for existing entities
   219→     * @param entries Array of glossary entries to create
   220→     * @returns DatabaseResult with creation statistics
   221→     */
   222→    async batchCreateGlossaryEntriesOptimized(entries: GlossaryEntryData[]): Promise<DatabaseResult<GlossaryCreateResult>> {
   223→        try {
   224→            // Input validation
   225→            if (!Array.isArray(entries)) {
   226→                return {
   227→                    success: false,
   228→                    error: 'Input must be an array of glossary entries'
   229→                };
   230→            }
   231→
   232→            if (entries.length === 0) {
   233→                return {
   234→                    success: true,
   235→                    data: {
   236→                        total: 0,
   237→                        committed: 0,
   238→                        failed: 0,
   239→                        errors: {}
   240→                    }
   241→                };
   242→            }
   243→
   244→            this.logger.log(`Processing ${entries.length} glossary entries`);
   245→
   246→            // Prepare entries for batch processing
   247→            const processedEntries = entries.map(entry => {
   248→                if (!entry.wordnv) {
   249→                    throw new Error(`Invalid entry: missing term property`);
   250→                }
   251→
   252→                return {
   253→                    wordnv: entry.wordnv.trim(),
   254→                    acronym: entry.acronym?.trim() || null,
   255→                    posnv: entry.posnv?.trim() || null,
   256→                    tag: entry.tag?.trim() || null,
   257→                    meaning: entry.meaning?.trim() || null,
   258→                    category: entry.category?.trim() || null,
   259→                    taxonomy_l1: entry.taxonomy_l1?.trim() || null,
   260→                    taxonomy_l2: entry.taxonomy_l2?.trim() || null,
   261→                    taxonomy_l3: entry.taxonomy_l3?.trim() || null,
   262→                    hasAcronym: !!(entry.acronym && entry.acronym !== 'Nill'),
   263→                    acronymMeaning: entry.meaning?.trim() || entry.wordnv.trim()
   264→                };
   265→            });
   266→
   267→            // Execute the batch creation query
   268→            const result = await this.neo4jService.write(TERMS_QUERIES.BATCH_CREATE_GLOSSARY_COMPLETE, {
   269→                entries: processedEntries
   270→            });
   271→
   272→            // Extract APOC iterate results
   273→            if (!result.records || result.records.length === 0) {
   274→                throw new Error('No results returned from batch creation query');
   275→            }
   276→
   277→            const record = result.records[0];
   278→            const operationsInfo = record.get('operations') || {};
   279→
   280→            return {
   281→                success: true,
   282→                data: {
   283→                    ...operationsInfo
   284→                }
   285→            };
   286→
   287→        } catch (error) {
   288→            this.logger.error('Batch creation failed', {
   289→                error: error instanceof Error ? error.message : String(error),
   290→                stack: error instanceof Error ? error.stack : undefined,
   291→                entriesCount: entries?.length || 0
   292→            });
   293→
   294→            return {
   295→                success: false,
   296→                error: `Batch creation failed: ${error instanceof Error ? error.message : String(error)}`
   297→            };
   298→        }
   299→    }
