    17→type BasicIdentifier = { sourceId: string; name: string };
    18→@Injectable()
    19→export class DocumentRepository implements IDocument {
    20→
    21→    private readonly logger = new Logger(DocumentRepository.name);
    22→
    23→    constructor(private readonly neo4jService: Neo4jService) { }
    24→
    25→    async allDocuments(): Promise<DatabaseResult<BasicIdentifier[]>> {
    26→
    27→        try {
    28→            const result = await this.neo4jService.write(
    29→                DOCUMENT_QUERIES.ALL_DOCUMENTS,
    30→                {}
    31→            );
    32→
    33→            const data = Neo4jUtils.mapRecords<BasicIdentifier>(result, Neo4jUtils.createMapper<BasicIdentifier>({
    34→                sourceId: "sourceId",
    35→                name: "name"
    36→            }));
    37→
    38→            return {
    39→                success: true,
    40→                data: data.success ? (data.data ?? []) : []
    41→            };
    42→        } catch (error) {
    43→            this.logger.error(`Error trying to retrieve documents`, error);
    44→            return {
    45→                success: false,
    46→                error: `Error trying to retrieve documents: ${error.message}`
    47→            };
    48→        }
    49→    }
    50→
    51→    async documentCount(documentSourceId: string) {
    52→        const result = await this.neo4jService.read(DOCUMENT_QUERIES.DOCUMENT_COUNT, {
    53→            documentSourceId
    54→        });
    55→
    56→        return result
    57→    }
    58→
    59→    async hasDocument(documentId: string): Promise<DatabaseResult<ExistsResult>> {
    60→        try {
    61→            const result = await this.neo4jService.read(
    62→                DOCUMENT_QUERIES.HAS_DOCUMENT,
    63→                { documentId }
    64→            );
    65→
    66→            const exists = Neo4jUtils.extractSingleResult<boolean>(result, 'nodeExists');
    67→
    68→            return {
    69→                success: true,
    70→                data: { exists: exists ?? false }
    71→            };
    72→        } catch (err) {
    73→            this.logger.error(`Failed to check document ${documentId} existence`, err);
    74→            return {
    75→                success: false,
    76→                error: `Failed to check document ${documentId} existence`
    77→            };
    78→        }
    79→    }
    80→
    81→    async createDocument(document: DocumentMetadata): Promise<DatabaseResult<SourceId>> {
    82→        this.logger.verbose(`Creating doc, ${document.sourceId}, ${document.name}`);
    83→
    84→        try {
    85→            // Check if the document exists by sourceId
    86→            const existingDocResult = await this.neo4jService.read(
    87→                DOCUMENT_QUERIES.CHECK_DOCUMENT_EXISTS,
    88→                { sourceId: document.sourceId }
    89→            );
    90→
    91→            if (existingDocResult?.records.length === 1) {
    92→                this.logger.verbose(`Document ${document.sourceId} already exists`);
    93→                return {
    94→                    success: true,
    95→                    data: {
    96→                        sourceId: existingDocResult.records[0].get('sourceId')
    97→                    }
    98→                };
    99→            }
   100→
   101→            this.logger.verbose(`Document ${document.sourceId} about to be created`);
   102→
   103→            // If document doesn't exist, create it
   104→            const result = await this.neo4jService.write(
   105→                DOCUMENT_QUERIES.CREATE_DOCUMENT,
   106→                {
   107→                    sourceId: document.sourceId,
   108→                    name: document.name
   109→                }
   110→            );
   111→
   112→            const createdSourceId = Neo4jUtils.extractSingleResult<string>(result, 'sourceId');
   113→
   114→            if (!createdSourceId) {
   115→                return {
   116→                    success: false,
   117→                    error: `Failed to create document ${document.name}`
   118→                };
   119→            }
   120→
   121→            return {
   122→                success: true,
   123→                data: { sourceId: createdSourceId }
