     4→@Injectable()
     5→export class DocumentDatabaseInitService implements OnModuleInit {
     6→    private readonly logger = new Logger(DocumentDatabaseInitService.name);
     7→
     8→    constructor(private readonly neo4jService: Neo4jService) { }
