    17→    private async createIndexes(): Promise<void> {
    18→        const indexes = [
    19→            {
    20→                name: 'Document sourceId index',
    21→                query: 'CREATE INDEX IF NOT EXISTS FOR (d:Document) ON (d.sourceId)'
    22→            },
    23→            {
    24→                name: 'Document name index',
    25→                query: 'CREATE INDEX IF NOT EXISTS FOR (d:Document) ON (d.name)'
    26→            },
    27→            {
    28→                name: 'Document createdAt index',
    29→                query: 'CREATE INDEX IF NOT EXISTS FOR (d:Document) ON (d.createdAt)'
    30→            },
    31→            {
    32→                name: 'Text sourceId index',
    33→                query: 'CREATE INDEX IF NOT EXISTS FOR (t:Text) ON (t.sourceId)'
    34→            }
    35→        ];
    36→
    37→        for (const index of indexes) {
    38→            try {
    39→                this.logger.debug(`Creating ${index.name}...`);
    40→                await this.neo4jService.write(index.query);
    41→                this.logger.log(`✓ ${index.name} created successfully`);
